/**
 * Extrae el saldo del monedero desde la página actual.
 */
async function extractWalletBalance(page: Page, log: Logger): Promise<number | null> {
  const logLocal: Logger = (m) => log(`[wallet-extract] ${m}`)
  try {
    const text = await page.innerText('.DFC12').catch(() => '')
    if (!text) return null
    const clean = text.replace('$', '').replace(/,/g, '').trim()
    const val = parseFloat(clean)
    if (!isNaN(val)) {
      logLocal(`Saldo Monedero detectado: $${val}`)
      return val
    }
  } catch (e: any) {
    logLocal(`Aviso: No se pudo extraer saldo: ${e.message}`)
  }
  return null
}

